import template from "./arnowa-compliance-hint-card.html.twig";

const { Component } = Shopware;

Component.register("arnowa-compliance-hint-card", {
  template,

  inject: ["repositoryFactory"],

  props: {
    product: {
      type: Object,
      required: true,
    },
  },

  computed: {
    complianceHint() {
      if (!this.product.extensions) {
        this.product.extensions = {};
      }

      if (!this.product.extensions.arnowaComplianceHint) {
        const repository = this.repositoryFactory.create(
          "arnowa_compliance_hint",
        );

        const entity = repository.create(Shopware.Context.api);

        entity.productId = this.product.id;
        entity.productVersionId = this.product.versionId;

        this.product.extensions.arnowaComplianceHint = entity;
      }

      return this.product.extensions.arnowaComplianceHint;
    },

    isHintRequired() {
      return this.complianceHint?.hintRequired === true;
    },
  },

  watch: {
    complianceHint: {
      handler() {
        // Shopware Change Detection triggern
        this.product.extensions = {
          ...this.product.extensions,
        };
      },
      deep: true,
    },
  },
});
